query SendingReputation24h(
  $zoneTag: string
  $subdomain: string
  $datetimeStart: string
  $datetimeEnd: string
) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      emailSendingAdaptiveGroups(
        limit: 10000
        filter: {
          isNDR: 0
          isLastEvent: 1
          sendingDomain: $subdomain
          datetimeHour_geq: $datetimeStart
          datetimeHour_leq: $datetimeEnd
        }
      ) @connection(key: "SendingReputation24h") {
        count
        dimensions {
          status
        }
      }
    }
  }
}

