query ZoneRoutingSparkline(
  $zoneTag: string
  $dateStart: string
  $dateEnd: string
) {
  viewer {
    zones(filter: { zoneTag: $zoneTag }) {
      emailRoutingAdaptiveGroups(
        limit: 10000
        filter: { isNDR: 0, date_geq: $dateStart, date_leq: $dateEnd }
        orderBy: [date_DESC]
      ) @connection(key: "EmailRoutingSparkline") {
        count
        dimensions {
          timestamp: date
          status
        }
      }
    }
  }
}

